func TestClassifyAPIErrorSanitizesTransportURLCredentials(t *testing.T) {
	raw := `Get "https://api.namecheap.com/xml.response?ApiKey=super-secret-key&ApiUser=littlemight&UserName=littlemight": dial tcp: lookup api.namecheap.com: no such host`

	classified := classifyAPIError(fmt.Errorf("%s", raw), nil)
	got := classified.Error()

	if strings.Contains(got, "super-secret-key") {
		t.Fatalf("classified CLI error leaked ApiKey: %q", got)
	}
	if !strings.Contains(got, "ApiKey=[REDACTED]") {
		t.Fatalf("classified CLI error did not redact ApiKey query param: %q", got)
	}
}
